//! residual-divergence-dump — bisect single-station vs two-station handoff.
//!
//! TASK
//! ----
//! Two prior parity tests cover (a) kernel multi-chunk vs single-chunk and
//! (b) embedding merge correctness. This bin attacks the orthogonal axis:
//! does running the *same* per-token sequence through ONE pipeline (path A)
//! produce the same per-layer residual stream as splitting the layer range
//! across TWO pipelines with a handoff at layer 14 (path B)?
//!
//! METHODOLOGY
//! -----------
//! Path A:  one pipeline, embed once, then call
//!          forward_range_chunk(input=residual_{l-1}, l, l+1, 0, seq_len)
//!          for l in 0..total_layers.
//!
//! Path B:  two pipelines (independent KV caches). Embed once per pipeline
//!          (deterministic, embed table is read-only). For l in 0..14, run
//!          on pipeline_1; for l in 14..total_layers, run on pipeline_2.
//!          The output of pipeline_1 layer 13 is fed as input to
//!          pipeline_2 layer 14 (this is the "handoff" — the wire payload
//!          a fat-station / cobordism mesh would actually carry).
//!
//! At every layer boundary we print first 4 floats of the residual on both
//! paths plus cosine + max-abs-delta. The FIRST layer N where A vs B differ
//! is the bug.
//!
//! API NOTE
//! --------
//! forward_range_chunk(input, start_layer, end_layer, start_pos, seq_len)
//! ALWAYS returns Vec<f32> of length seq_len*hidden_dim — see
//! src/model.rs lines 1847-1850 (`out.copy_from_slice(&self.batch_x[..])`).
//! So per-layer instrumentation is just calling it with start=l, end=l+1.
//!
//! Usage:
//!   cargo run --release --bin residual-divergence-dump -- /tmp/qwen-coder-7b.knot

use std::env;

use distributed_inference::loader::KnotWeights;
use distributed_inference::NativeLlamaPipeline;

const HANDOFF_LAYER: usize = 14;

fn cosine(a: &[f32], b: &[f32]) -> f32 {
    let mut dot = 0.0f64;
    let mut na = 0.0f64;
    let mut nb = 0.0f64;
    for i in 0..a.len() {
        let av = a[i] as f64;
        let bv = b[i] as f64;
        dot += av * bv;
        na += av * av;
        nb += bv * bv;
    }
    let denom = na.sqrt() * nb.sqrt();
    if denom == 0.0 {
        return 0.0;
    }
    (dot / denom) as f32
}

fn max_abs_delta(a: &[f32], b: &[f32]) -> f32 {
    let mut m = 0.0f32;
    for i in 0..a.len() {
        let d = (a[i] - b[i]).abs();
        if d > m {
            m = d;
        }
    }
    m
}

fn first4(v: &[f32]) -> String {
    if v.len() < 4 {
        return format!("{:?}", v);
    }
    format!("[{:+.6}, {:+.6}, {:+.6}, {:+.6}]", v[0], v[1], v[2], v[3])
}

fn first16(v: &[f32]) -> String {
    let n = v.len().min(16);
    let parts: Vec<String> = v[..n].iter().map(|x| format!("{:+.6}", x)).collect();
    format!("[{}]", parts.join(", "))
}

fn finite_check(name: &str, v: &[f32]) {
    let mut nan = 0usize;
    let mut inf = 0usize;
    for &x in v {
        if x.is_nan() {
            nan += 1;
        } else if x.is_infinite() {
            inf += 1;
        }
    }
    if nan > 0 || inf > 0 {
        println!("        WARN[{}] nan={} inf={}", name, nan, inf);
    }
}

fn main() -> Result<(), String> {
    let args: Vec<String> = env::args().collect();
    if args.len() < 2 {
        return Err(format!(
            "usage: {} <knot.path>",
            args.first()
                .map(String::as_str)
                .unwrap_or("residual-divergence-dump")
        ));
    }
    let knot_path = args[1].clone();

    // 4 hand-rolled token IDs in qwen2 vocab range (151,936).
    let tokens: Vec<u32> = vec![1234, 2345, 3456, 4567];
    let seq_len = tokens.len();

    println!("============================================================");
    println!(" residual-divergence-dump");
    println!("   knot          : {}", knot_path);
    println!("   tokens        : {:?}", tokens);
    println!(
        "   handoff layer : {} (path B switches pipelines here)",
        HANDOFF_LAYER
    );
    println!("============================================================");

    // Sanity-load and read config.
    let (hidden_dim, total_layers) = {
        let knot = KnotWeights::load(&knot_path)?;
        let cfg = knot.config.as_ref().ok_or("no config block in knot")?;
        println!(
            "[meta] hidden={} layers={} heads={} kv={} head_dim={} ffn={} vocab={} rope={}",
            cfg.hidden_dim,
            cfg.num_layers,
            cfg.num_heads,
            cfg.num_kv_heads,
            cfg.head_dim,
            cfg.intermediate_size,
            cfg.vocab_size,
            cfg.rope_theta,
        );
        (cfg.hidden_dim, cfg.num_layers)
    };

    if HANDOFF_LAYER >= total_layers {
        return Err(format!(
            "HANDOFF_LAYER={} >= total_layers={}; pick a smaller layer",
            HANDOFF_LAYER, total_layers
        ));
    }

    // ------------------------------------------------------------------
    // Path A: one pipeline, per-layer.
    // ------------------------------------------------------------------
    let knot_a = KnotWeights::load(&knot_path)?;
    let mut pipe_a = NativeLlamaPipeline::from_knot(knot_a, false, 0.0);
    let emb_a = pipe_a.embed_chunk(&tokens, 0)?;

    // ------------------------------------------------------------------
    // Path B: two pipelines (independent KV). Handoff at HANDOFF_LAYER.
    // Both pipelines start with their OWN embedding (deterministic — the
    // embedding table is read-only and identical across loads).
    // ------------------------------------------------------------------
    let knot_b1 = KnotWeights::load(&knot_path)?;
    let mut pipe_b1 = NativeLlamaPipeline::from_knot(knot_b1, false, 0.0);
    let emb_b1 = pipe_b1.embed_chunk(&tokens, 0)?;

    let knot_b2 = KnotWeights::load(&knot_path)?;
    let mut pipe_b2 = NativeLlamaPipeline::from_knot(knot_b2, false, 0.0);
    // pipe_b2's embed step is run for fairness (in the real mesh, the
    // second station never embeds — it receives a residual stream — but
    // calling embed_chunk has no side effect on subsequent
    // forward_range_chunk calls because the latter overwrites batch_x
    // from its `input` argument).
    let _ = pipe_b2.embed_chunk(&tokens, 0)?;

    // Quick sanity: emb_a vs emb_b1 should be identical (same knot, same
    // tokens). If they differ, the embedding lookup itself is non-determ.
    {
        let cos = cosine(&emb_a, &emb_b1);
        let mxa = max_abs_delta(&emb_a, &emb_b1);
        println!(
            "[embed] cos(emb_A, emb_B1) = {:.8}   max-abs-delta = {:.8}",
            cos, mxa
        );
    }

    // Walk layers one at a time.
    let mut residual_a: Vec<f32> = emb_a.clone();
    let mut residual_b: Vec<f32> = emb_b1.clone();

    println!("\n----- per-layer residual divergence -----");
    println!(
        "{:>5} | {:^48} | {:^48} | {:>10} {:>10}",
        "layer", "A first4", "B first4", "cos", "max-abs"
    );
    println!("{}", "-".repeat(132));

    let mut first_divergence: Option<usize> = None;

    for l in 0..total_layers {
        // Path A: always pipe_a.
        residual_a = pipe_a.forward_range_chunk(&residual_a, l, l + 1, 0, seq_len)?;

        // Path B: layers 0..HANDOFF_LAYER on pipe_b1, then pipe_b2.
        residual_b = if l < HANDOFF_LAYER {
            pipe_b1.forward_range_chunk(&residual_b, l, l + 1, 0, seq_len)?
        } else {
            // First call on pipe_b2: residual_b is whatever pipe_b1 last
            // produced (output of layer HANDOFF_LAYER-1). pipe_b2 owns
            // layers HANDOFF_LAYER..total_layers; its KV cache is empty
            // until this call (which writes positions 0..seq_len for
            // layer l).
            pipe_b2.forward_range_chunk(&residual_b, l, l + 1, 0, seq_len)?
        };

        finite_check(&format!("A_l{}", l), &residual_a);
        finite_check(&format!("B_l{}", l), &residual_b);

        let cos = cosine(&residual_a, &residual_b);
        let mxa = max_abs_delta(&residual_a, &residual_b);
        let marker = if l == HANDOFF_LAYER {
            " <-- HANDOFF"
        } else {
            ""
        };
        println!(
            "{:>5} | {:<48} | {:<48} | {:>10.6} {:>10.6}{}",
            l,
            first4(&residual_a[..hidden_dim.min(residual_a.len())]),
            first4(&residual_b[..hidden_dim.min(residual_b.len())]),
            cos,
            mxa,
            marker
        );

        // Threshold: cos < 0.9999 OR max-abs > 1e-3 counts as divergence.
        // Rationale: pure same-kernel parity should be bit-identical
        // modulo rayon non-determinism; even rayon noise is < 1e-5.
        if first_divergence.is_none() && (cos < 0.9999 || mxa > 1e-3) {
            first_divergence = Some(l);
            println!("\n        >>> FIRST DIVERGENCE at layer {} <<<", l);
            println!(
                "        A first16 (token 0): {}",
                first16(&residual_a[..hidden_dim.min(16).min(residual_a.len())])
            );
            println!(
                "        B first16 (token 0): {}",
                first16(&residual_b[..hidden_dim.min(16).min(residual_b.len())])
            );
            // Also dump a later token's first-4 to see if it's prompt-pos
            // dependent.
            if seq_len > 1 {
                let off = (seq_len - 1) * hidden_dim;
                println!(
                    "        A first4 (token {}, last): {}",
                    seq_len - 1,
                    first4(&residual_a[off..off + hidden_dim.min(4)])
                );
                println!(
                    "        B first4 (token {}, last): {}",
                    seq_len - 1,
                    first4(&residual_b[off..off + hidden_dim.min(4)])
                );
            }
            println!();
        }
    }

    println!("\n============================================================");
    match first_divergence {
        Some(l) => {
            println!(" RESULT: FIRST DIVERGENCE at layer {}", l);
            if l == HANDOFF_LAYER {
                println!("        ==> divergence at exactly the handoff layer");
                println!("            -> bug is in the cross-pipeline transition (KV-cache");
                println!("               state on pipe_b2 is empty / different from pipe_a).");
            } else if l < HANDOFF_LAYER {
                println!(
                    "        ==> divergence BEFORE handoff (l < {})",
                    HANDOFF_LAYER
                );
                println!("            -> two `from_knot` builds produce non-identical state.");
            } else {
                println!(
                    "        ==> divergence AFTER handoff (l > {})",
                    HANDOFF_LAYER
                );
                println!("            -> handoff itself was clean but pipe_b2 diverges later;");
                println!("               likely KV-cache or layer-index bookkeeping in pipe_b2.");
            }
        }
        None => {
            println!(" RESULT: NO DIVERGENCE through {} layers", total_layers);
            println!("        Path A and Path B match to within cos>=0.9999 max-abs<=1e-3");
            println!("        on every layer including the handoff. The two-station mesh");
            println!("        kernel is innocent; bug is somewhere in the wire / dispatch.");
        }
    }
    println!("============================================================");

    Ok(())
}
